code.perFrame:
zoom = 0.99951;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
//spiral collide frame;
t = t + 2.5/fps;;
t = if(((t) > (2)),t-2,t);;
q22 = -t;;
// Flexis dampened sound response functions;
db = db*0.98 + bass_att*0.2; // dampener;
bb = bb + db*0.1; // accumulation, replace time expressions with this ;);
dt = dt*0.98 + treb_att*0.2;;
tt = tt + dt*0.1;;
dm = dm*0.98 + mid_att*0.2;;
mm = mm + dm*0.1;;
//***** [q11-q18] variables for Flexis caleidoscope shader code *****;
// change;
q13 = 0.5 + sin((bb-mm)*0.1)*0.25; // center x;
q14 = 0.5 + sin((tt-mm)*0.1)*0.25; // center y;
w = (bb-tt)*0.1;                   // angle;
q16 = 0.8 - (db-dt)*0.04;         // size;
//don't change;
q11 = sin(w);;
q12 = cos(w);;
q17 = sin(-w);;
q18 = cos(-w);;
q15 = 1/q16;;
db=bass-lbass;;
lbass=bass;;
vol=1+bass+mid+treb;;
maxdb=max(maxdb*.9999,abs(db));;
rs=((abs(db)) > (maxdb));;
drs=1-rs;;
beatrate=1*rs+beatrate*drs;;
avgbeatrate=1*rs+avgbeatrate*drs;;
bbtime=1*rs+bbtime*drs;;
lbbtime=1*rs+lbbtime*drs;;
avgdb=1*rs+avgdb*drs;;
bc=bc*drs+1*rs;;
avgdb=avgdb*.999+abs(db)*.001;;
rawbeatb=((db) > (avgdb*1.3));;
beatb=rawbeatb*((time-lbbtime) > (.5*avgbeatrate));;
bbtime=time*beatb;;
beatrate=beatb*(bbtime-lbbtime)+(1-beatb)*beatrate;;
avgbeatrate=beatb*(avgbeatrate*.999+beatrate*.001)+(1-beatb)*avgbeatrate;;
lbbtime=time*beatb+(1-beatb)*lbbtime;;
cc=bc+beatb;;
q5=beatb;;
q1=time*.001*avgdb*avgbeatrate;;
q2=((bc%4) == (0))*beatb;;
q3=bc;;
q4=60/avgbeatrate;;
monitor=bc;;
decay=1;;
warp=0;;
wrap=1;;
cr1=cr1*(1-q2)+(1-cr1)*q2;;
cr2=cr2*(1-q2)+(1-cr2)*q2;;
q6=cr2;;
q8=cr1;;
q7=1-cr1;;
q6=sin(time*q4*.1);;
cc=sin(bc*.3);;
zoomexp=150*(1-cc)+cc*.1;
